use super::super::super::{DeploymentManifest, SIGNER_SIDECAR_ROOT};
use super::super::quote::ps_literal;

pub(in crate::private_network) fn render_windows_health_script(
    manifest: &DeploymentManifest,
) -> String {
    let mut text = format!(
        "$ErrorActionPreference = 'Stop'\n\n# Generated by NeoNexus for {} / magic {}.\nSet-Location $PSScriptRoot\n$TimeoutSeconds = 60\nif (![string]::IsNullOrWhiteSpace($env:NEONEXUS_HEALTH_TIMEOUT_SECONDS)) {{\n    $TimeoutSeconds = [int]$env:NEONEXUS_HEALTH_TIMEOUT_SECONDS\n}}\n$IntervalSeconds = 2\nif (![string]::IsNullOrWhiteSpace($env:NEONEXUS_HEALTH_INTERVAL_SECONDS)) {{\n    $IntervalSeconds = [int]$env:NEONEXUS_HEALTH_INTERVAL_SECONDS\n}}\n$Deadline = (Get-Date).AddSeconds($TimeoutSeconds)\n$Failures = 0\n\nfunction Ok-NeoNexusHealth {{\n    param([string]$Message)\n    Write-Host \"OK: $Message\"\n}}\n\nfunction Warn-NeoNexusHealth {{\n    param([string]$Message)\n    Write-Host \"WARN: $Message\"\n}}\n\nfunction Fail-NeoNexusHealth {{\n    param([string]$Message)\n    Write-Host \"FAIL: $Message\"\n    $script:Failures += 1\n}}\n\nfunction Test-NeoNexusPidFileAlive {{\n    param([string]$PidFile)\n    if (!(Test-Path -LiteralPath $PidFile -PathType Leaf)) {{ return $false }}\n    $pidValue = (Get-Content -LiteralPath $PidFile -Raw).Trim()\n    if ([string]::IsNullOrWhiteSpace($pidValue)) {{ return $false }}\n    $process = Get-Process -Id ([int]$pidValue) -ErrorAction SilentlyContinue\n    return ($null -ne $process)\n}}\n\nfunction Test-NeoNexusPidAlive {{\n    param([string]$Name, [string]$WorkDir)\n    return (Test-NeoNexusPidFileAlive -PidFile (Join-Path $WorkDir \"$Name.pid\"))\n}}\n\nfunction Test-NeoNexusSignerPidAlive {{\n    param([string]$Label)\n    return (Test-NeoNexusPidFileAlive -PidFile (Join-Path (Join-Path '{SIGNER_SIDECAR_ROOT}' $Label) \"$Label.pid\"))\n}}\n\nfunction Test-NeoNexusTcpOpen {{\n    param([int]$Port)\n    $client = [System.Net.Sockets.TcpClient]::new()\n    try {{\n        $task = $client.ConnectAsync('127.0.0.1', $Port)\n        if (!$task.Wait(1000)) {{ return $false }}\n        return $client.Connected\n    }} catch {{\n        return $false\n    }} finally {{\n        $client.Dispose()\n    }}\n}}\n\nfunction Test-NeoNexusHttpReady {{\n    param([string]$Endpoint)\n    try {{\n        Invoke-WebRequest -Method Get -Uri $Endpoint -TimeoutSec 2 -UseBasicParsing | Out-Null\n        return $true\n    }} catch {{\n        return $false\n    }}\n}}\n\nfunction Test-NeoNexusRpcReady {{\n    param([int]$Port)\n    $body = '{{\"jsonrpc\":\"2.0\",\"method\":\"getblockcount\",\"params\":[],\"id\":1}}'\n    try {{\n        Invoke-RestMethod -Method Post -Uri \"http://127.0.0.1:$Port\" -Body $body -ContentType 'application/json' -TimeoutSec 2 | Out-Null\n        return $true\n    }} catch {{\n        return $false\n    }}\n}}\n\nfunction Wait-NeoNexusSigner {{\n    param([string]$Label, [string]$Endpoint)\n    while ((Get-Date) -le $Deadline) {{\n        if (Test-NeoNexusSignerPidAlive -Label $Label) {{\n            if ($Endpoint -eq '-') {{\n                Ok-NeoNexusHealth \"signer $Label process is healthy\"\n                return\n            }}\n            if (Test-NeoNexusHttpReady -Endpoint $Endpoint) {{\n                Ok-NeoNexusHealth \"signer $Label endpoint is healthy\"\n                return\n            }}\n        }}\n        Start-Sleep -Seconds $IntervalSeconds\n    }}\n    Fail-NeoNexusHealth \"signer $Label did not become healthy within $TimeoutSeconds seconds\"\n}}\n\nfunction Test-NeoNexusNodeReady {{\n    param([string]$Name, [string]$WorkDir, [int]$RpcPort, [int]$P2pPort, [int]$WsPort)\n    if (!(Test-NeoNexusPidAlive -Name $Name -WorkDir $WorkDir)) {{ return $false }}\n    if (!(Test-NeoNexusTcpOpen -Port $RpcPort)) {{ return $false }}\n    if (!(Test-NeoNexusTcpOpen -Port $P2pPort)) {{ return $false }}\n    if ($WsPort -ne 0 -and !(Test-NeoNexusTcpOpen -Port $WsPort)) {{ return $false }}\n    return (Test-NeoNexusRpcReady -Port $RpcPort)\n}}\n\nfunction Wait-NeoNexusNode {{\n    param([string]$Name, [string]$WorkDir, [int]$RpcPort, [int]$P2pPort, [int]$WsPort)\n    while ((Get-Date) -le $Deadline) {{\n        if (Test-NeoNexusNodeReady -Name $Name -WorkDir $WorkDir -RpcPort $RpcPort -P2pPort $P2pPort -WsPort $WsPort) {{\n            Ok-NeoNexusHealth \"$Name is healthy\"\n            return\n        }}\n        Start-Sleep -Seconds $IntervalSeconds\n    }}\n    Fail-NeoNexusHealth \"$Name did not become healthy within $TimeoutSeconds seconds\"\n}}\n\n",
        manifest.runtime, manifest.network_magic
    );
    append_windows_health_signers(&mut text, manifest);
    for node in &manifest.nodes {
        text.push_str(&format!(
            "Wait-NeoNexusNode -Name {} -WorkDir {} -RpcPort {} -P2pPort {} -WsPort {}\n",
            ps_literal(&node.name),
            ps_literal(&node.working_dir),
            node.rpc_port,
            node.p2p_port,
            node.ws_port.unwrap_or(0)
        ));
    }
    text.push_str(
        "\nif ($Failures -ne 0) {\n    Write-Host 'Health check failed'\n    exit 1\n}\n\nWrite-Host 'Health check passed'",
    );
    text
}

fn append_windows_health_signers(text: &mut String, manifest: &DeploymentManifest) {
    let signers = manifest
        .committee
        .signers
        .iter()
        .filter(|signer| signer.signer_command_plan.is_some())
        .collect::<Vec<_>>();
    if signers.is_empty() {
        return;
    }
    text.push_str("# Committee signer sidecar health\n");
    for signer in signers {
        text.push_str(&format!(
            "Wait-NeoNexusSigner -Label {} -Endpoint {}\n",
            ps_literal(&signer.label),
            ps_literal(signer.signer_endpoint.as_deref().unwrap_or("-"))
        ));
    }
    text.push('\n');
}
